import React, { useState, useEffect } from 'react';
import axios from 'axios';

const RegistroEmpresa = ({ ancho = '100%', alto = '100%' }) => {
  const [form, setForm] = useState({
    denominacion_social: '',
    nombre_comercial: '',
    nit: '',
    url: '',
    eslogan: '',
    descripcion: '',
    fecha_fundacion: '',
    fecha_cierre: '',
    rubros: [],
    premios: [],
    actividades: [],
    tamanios: [],
    tipos_societarios: [],
    propietarios: []
  });

  const [rubrosDisponibles, setRubrosDisponibles] = useState([]);
  const [premiosDisponibles, setPremiosDisponibles] = useState([]);

  const handleInput = (field, value) => {
    setForm({ ...form, [field]: value });
  };

  const toggleCheckbox = (field, value) => {
    const current = form[field] || [];
    const updated = current.includes(value)
      ? current.filter((v) => v !== value)
      : [...current, value];

    setForm({ ...form, [field]: updated });
  };

  const fetchDatos = async () => {
    try {
      const [rubrosRes, premiosRes] = await Promise.all([
        axios.get('http://localhost:3000/rubros'),
        axios.get('http://localhost:3000/premios')
      ]);
      setRubrosDisponibles(rubrosRes.data);
      setPremiosDisponibles(premiosRes.data.premios);
    } catch (error) {
      console.error('Error al cargar datos auxiliares:', error);
    }
  };

  useEffect(() => {
    fetchDatos();
  }, []);

  const enviarFormulario = async () => {
    try {
      await axios.post('http://localhost:3000/empresa', form);
      alert('Empresa registrada correctamente ✅');
    } catch (error) {
      console.error('Error al registrar empresa:', error);
      alert('Error al registrar empresa ❌');
    }
  };

  return (
    <div style={{ width: ancho, height: alto }} className="overflow-y-auto p-4 border rounded bg-white">
      <h2 className="text-xl font-bold mb-4">Registro de Empresa</h2>

      <input type="text" value={form.nombre_comercial} onChange={(e) => handleInput('nombre_comercial', e.target.value)} placeholder="Nombre Comercial" className="w-full p-2 border rounded mb-2" />
      <input type="text" value={form.denominacion_social} onChange={(e) => handleInput('denominacion_social', e.target.value)} placeholder="Denominación Social" className="w-full p-2 border rounded mb-2" />
      <input type="text" value={form.nit} onChange={(e) => handleInput('nit', e.target.value)} placeholder="NIT" className="w-full p-2 border rounded mb-2" />
      <input type="text" value={form.url} onChange={(e) => handleInput('url', e.target.value)} placeholder="Imagen (URL en Cloudinary)" className="w-full p-2 border rounded mb-2" />
      <input type="text" value={form.eslogan} onChange={(e) => handleInput('eslogan', e.target.value)} placeholder="Eslogan" className="w-full p-2 border rounded mb-2" />
      <textarea value={form.descripcion} onChange={(e) => handleInput('descripcion', e.target.value)} placeholder="Descripción" className="w-full p-2 border rounded mb-2" />
      <input type="date" value={form.fecha_fundacion} onChange={(e) => handleInput('fecha_fundacion', e.target.value)} className="w-full p-2 border rounded mb-2" />
      <input type="date" value={form.fecha_cierre} onChange={(e) => handleInput('fecha_cierre', e.target.value)} className="w-full p-2 border rounded mb-2" />

      <div className="mb-4">
        <label className="font-semibold block">Rubros:</label>
        <div className="flex flex-wrap gap-2">
          {rubrosDisponibles.map((rubro) => (
            <label key={rubro.id_rubro}>
              <input
                type="checkbox"
                checked={form.rubros.includes(rubro.nombre_rubro)}
                onChange={() => toggleCheckbox('rubros', rubro.nombre_rubro)}
              />
              <span className="ml-1">{rubro.nombre_rubro}</span>
            </label>
          ))}
        </div>
      </div>

      <div className="mb-4">
        <label className="font-semibold block">Premios:</label>
        <div className="flex flex-col gap-1 max-h-[150px] overflow-y-auto">
          {premiosDisponibles.map((premio) => (
            <label key={premio.id_premio} className="text-sm">
              <input
                type="checkbox"
                checked={form.premios.includes(premio.descripcion)}
                onChange={() => toggleCheckbox('premios', premio.descripcion)}
              />
              <span className="ml-2">{premio.descripcion} ({premio.entidad_otorgadora})</span>
            </label>
          ))}
        </div>
      </div>

      <button onClick={enviarFormulario} className="mt-4 px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded">
        Registrar Empresa
      </button>
    </div>
  );
};

export default RegistroEmpresa;
